import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.9L5wI8-n.js";const d=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"usage/quick-start.md","filePath":"usage/quick-start.md"}'),r={name:"usage/quick-start.md"};function n(s,e,l,u,p,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>Get AI Image Renamer up and running in under 2 minutes.</p><h2 id="step-1-activate-the-plugin" tabindex="-1">Step 1: Activate the Plugin <a class="header-anchor" href="#step-1-activate-the-plugin" aria-label="Permalink to &quot;Step 1: Activate the Plugin&quot;">​</a></h2><p>After <a href="/wp-ai-image-renamer/usage/installation.html">installing</a> the plugin, make sure it&#39;s activated in <strong>Plugins → Installed Plugins</strong>.</p><h2 id="step-2-enter-your-api-key" tabindex="-1">Step 2: Enter Your API Key <a class="header-anchor" href="#step-2-enter-your-api-key" aria-label="Permalink to &quot;Step 2: Enter Your API Key&quot;">​</a></h2><ol><li>Navigate to <strong>Media → AI Image Renamer</strong></li><li>Paste your Groq API key (starts with <code>gsk_</code>) into the <strong>Groq API Key</strong> field</li><li>Click <strong>&quot;Test Connection&quot;</strong> to verify it works</li><li>Click <strong>&quot;Save Changes&quot;</strong></li></ol><div class="tip custom-block"><p class="custom-block-title">Don&#39;t have a key yet?</p><p>Get one for free at <a href="https://console.groq.com/keys" target="_blank" rel="noreferrer">console.groq.com/keys</a>. No credit card required.</p></div><h2 id="step-3-enable-auto-rename" tabindex="-1">Step 3: Enable Auto-Rename <a class="header-anchor" href="#step-3-enable-auto-rename" aria-label="Permalink to &quot;Step 3: Enable Auto-Rename&quot;">​</a></h2><p>Toggle the <strong>&quot;Enable Auto-Rename&quot;</strong> switch to <strong>ON</strong> and save.</p><h2 id="step-4-upload-an-image" tabindex="-1">Step 4: Upload an Image <a class="header-anchor" href="#step-4-upload-an-image" aria-label="Permalink to &quot;Step 4: Upload an Image&quot;">​</a></h2><p>Go to <strong>Media → Add New</strong> and upload any image. The plugin will automatically:</p><ol><li>Send the image to Groq&#39;s Vision API</li><li>Analyze the image content</li><li>Rename the file with descriptive, SEO-friendly keywords</li></ol><p><strong>Before:</strong> <code>IMG_20260215_143052.jpg</code><strong>After:</strong> <code>sunset-over-tropical-beach-palm-trees.jpg</code></p><h2 id="what-s-next" tabindex="-1">What&#39;s Next? <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next?&quot;">​</a></h2><ul><li><a href="/wp-ai-image-renamer/usage/settings.html">Configure settings</a> — Choose your AI model, file types, and keyword limits</li><li><a href="/wp-ai-image-renamer/api/filter-hooks.html">Explore hooks</a> — Customize the plugin&#39;s behavior with filters and actions</li><li><a href="/wp-ai-image-renamer/api/examples.html">See examples</a> — Learn how to extend the plugin for your specific needs</li></ul>',15)])])}const g=t(r,[["render",n]]);export{d as __pageData,g as default};
